<script setup lang="ts">import type { PolicyScopeVisualDocument } from '#/api/system/bpm/policy'; import { ElFormItem,ElOption,ElSelect } from 'element-plus'; import BpmIdentityPicker from '#/components/bpm/identity/bpm-identity-picker.vue'; const props=defineProps<{label:string}>(); const model=defineModel<PolicyScopeVisualDocument>({required:true});</script>
